CREATE TRIGGER LG_KSLINES_UPD_001_01 ON LG_001_01_KSLINES
FOR UPDATE
AS
DECLARE @TRCODE    SMALLINT
DECLARE @TRDATE    DATETIME
DECLARE @TRSIGN    SMALLINT
DECLARE @CASHREF   INT
DECLARE @AMOUNT    FLOAT
DECLARE @REPORTNET FLOAT
DECLARE @TRNET FLOAT
DECLARE @TRCURR SMALLINT
DECLARE @CANCELLED SMALLINT
DECLARE @STATUS    SMALLINT
SELECT @TRCODE    = D.TRCODE,
       @TRDATE    = D.DATE_,
       @TRSIGN    = D.SIGN,
       @CASHREF   = D.CARDREF,
       @AMOUNT    = D.AMOUNT,
       @REPORTNET = D.REPORTNET,
       @TRNET     = D.TRNET,
       @TRCURR    = D.TRCURR,
       @CANCELLED = D.CANCELLED,
       @STATUS    = D.STATUS FROM DELETED D
EXECUTE LG_UPDATE_CASHTRANS_001_01 -1, @TRCODE, @TRDATE, @TRSIGN, @CASHREF, @AMOUNT, @REPORTNET, @TRNET, @TRCURR, @CANCELLED, @STATUS
SELECT @TRCODE    = I.TRCODE,
       @TRDATE    = I.DATE_,
       @TRSIGN    = I.SIGN,
       @CASHREF   = I.CARDREF,
       @AMOUNT    = I.AMOUNT,
       @REPORTNET = I.REPORTNET,
       @TRNET     = I.TRNET,
       @TRCURR    = I.TRCURR,
       @CANCELLED = I.CANCELLED,
       @STATUS    = I.STATUS FROM INSERTED I
EXECUTE LG_UPDATE_CASHTRANS_001_01 1, @TRCODE, @TRDATE, @TRSIGN, @CASHREF, @AMOUNT, @REPORTNET, @TRNET, @TRCURR, @CANCELLED, @STATUS
